export const ListRevenueEventsQueryParams = zod.object({
  type: zod
    .enum([
      "payment",
      "cancellation",
      "upgrade",
      "downgrade",
      "refund",
      "new_subscription",
    ])
    .optional(),
  limit: zod.coerce.number().default(listRevenueEventsQueryLimitDefault),
  offset: zod.coerce.number().default(listRevenueEventsQueryOffsetDefault),
});

export const listRevenueEventsResponseEventsItemCurrencyDefault = `BRL`;

export const ListRevenueEventsResponse = zod.object({
  events: zod.array(
    zod.object({
      id: zod.string(),
      projectId: zod.string(),
      type: zod.enum([
        "payment",
        "cancellation",
        "upgrade",
        "downgrade",
        "refund",
        "new_subscription",
      ]),
      amount: zod.number(),
      currency: zod
        .string()
        .default(listRevenueEventsResponseEventsItemCurrencyDefault),
      customerId: zod.string().optional(),
      customerEmail: zod.string().optional(),
      plan: zod.string().optional(),
      description: zod.string().optional(),
      externalId: zod.string().optional(),
      source: zod.enum(["abacatepay", "manual", "api"]),
      timestamp: zod.date(),
      metadata: zod.record(zod.string(), zod.unknown()).optional(),
    }),
  ),
  total: zod.number(),
  limit: zod.number(),
  offset: zod.number(),
});

